      . "Options:\n"
      . "  --compress   Create a compressed tar.gz backup (default)\n"
      . "  --checksum   Generate MD5 checksum of the backup\n"
      . "  --list       List contents of existing backup archive\n"
      . "  --backup-all Backup, compress, checksum, and verify\n";
