# Subroutine to create compressed tar backup
sub create_backup {
    my ($source, $dest) = @_;
    print "Creating compressed backup of '$source'...\n";
    print "Destination: $dest\n";

    # Use system() for command execution with proper error handling
    my $cmd = "tar -czf \Q$dest\E \Q$source\E";
    print "Executing: $cmd\n";

    my $exit_code = system($cmd);

    if ($exit_code == 0) {
        # Use backticks to capture the file size
        my $size = `ls -lh \Q$dest\E | awk '{print \$5}'`;
        chomp $size;
        print "Backup created successfully: $dest (Size: $size)\n";
        return 1;
    } elsif ($exit_code == -1) {
        die "Error: Failed to execute tar command: $!\n";
    } else {
        my $signal = $exit_code & 127;
        my $return_val = $exit_code >> 8;
        die "Error: tar command failed with exit code $return_val (signal: $signal)\n";
    }
}

# Subroutine to generate MD5 checksum
sub generate_checksum {
    my ($file) = @_;
    print "Generating MD5 checksum for '$file'...\n";

    # Detect available checksum utility
    my $md5_cmd;
    if (`which md5sum 2>/dev/null`) {
        $md5_cmd = "md5sum";
    } elsif (`which md5 2>/dev/null`) {
        $md5_cmd = "md5";
    } else {
        warn "Warning: No MD5 utility found. Skipping checksum.\n";
        return;
    }

    # Use backticks to capture checksum output
    my $checksum_output = `$md5_cmd \Q$file\E 2>&1`;
    my $exit_status = $? >> 8;

    if ($exit_status == 0) {
        chomp $checksum_output;
        my $checksum_file = "${file}.md5";
        open(my $fh, '>', $checksum_file) or die "Cannot write checksum file: $!\n";
        print $fh "$checksum_output\n";
        close($fh);
        print "Checksum: $checksum_output\n";
        print "Checksum saved to: $checksum_file\n";
        return $checksum_output;
    } else {
        warn "Warning: Checksum generation failed: $checksum_output\n";
        return;
    }
}

# Subroutine to list contents of an archive
sub list_archive {
    my ($archive) = @_;

    if (!-e $archive) {
        die "Error: Archive '$archive' does not exist.\n";
    }

    print "Listing contents of '$archive':\n";
    print "-" x 60, "\n";

    # Use backticks to capture tar listing output
    my $listing = `tar -tzf \Q$archive\E 2>&1`;
    my $exit_status = $? >> 8;

    if ($exit_status == 0) {
        print $listing;
        # Count entries
        my @entries = split(/\n/, $listing);
        print "-" x 60, "\n";
        print "Total entries: " . scalar(@entries) . "\n";
    } else {
        die "Error listing archive: $listing\n";
    }
}

# Subroutine to verify the backup archive integrity
sub verify_backup {
    my ($archive) = @_;
    print "Verifying backup archive integrity...\n";

    # Use system() to test the archive
    my $exit_code = system("tar -tzf \Q$archive\E > /dev/null 2>&1");

    if ($exit_code == 0) {
        print "Verification: Archive '$archive' is valid.\n";
        return 1;
    } else {
        warn "Verification FAILED: Archive '$archive' may be corrupted!\n";
        return 0;
    }
}

# Subroutine to get disk usage information
sub disk_usage_info {
    my ($path) = @_;
    print "\nDisk usage information:\n";

    my $du_output = `du -sh \Q$path\E 2>&1`;
    chomp $du_output;
    print "  Source size: $du_output\n";

    my $df_output = `df -h \Q$backup_dir\E 2>&1 | tail -1`;
    chomp $df_output;
    print "  Backup disk: $df_output\n";
}

# Subroutine to clean old backups (keep last N)
sub cleanup_old_backups {
    my ($pattern, $keep_count) = @_;
    $keep_count ||= 5;

    print "\nChecking for old backups to clean up (keeping last $keep_count)...\n";

    my $find_cmd = "ls -1t ${backup_dir}/${pattern}*.tar.gz 2>/dev/null";
    my @backups = split(/\n/, `$find_cmd`);

    if (scalar(@backups) > $keep_count) {
        my @to_delete = @backups[$keep_count .. $#backups];
        for my $old_backup (@to_delete) {
            chomp $old_backup;
            print "  Removing old backup: $old_backup\n";
            unlink $old_backup or warn "  Warning: Could not remove $old_backup: $!\n";
            # Also remove associated checksum file
            if (-e "${old_backup}.md5") {
                unlink "${old_backup}.md5";
            }
        }
        print "  Cleaned up " . scalar(@to_delete) . " old backup(s).\n";
    } else {
        print "  No old backups to clean up.\n";
    }
}

# Log backup operation
sub log_backup {
    my ($message) = @_;
    my $log_file = "$backup_dir/backup.log";
    my $log_timestamp = strftime("%Y-%m-%d %H:%M:%S", localtime);

    open(my $fh, '>>', $log_file) or warn "Warning: Could not write to log file: $!\n";
    if ($fh) {
        print $fh "[$log_timestamp] $message\n";
        close($fh);
    }
}

